(window.webpackJsonp=window.webpackJsonp||[]).push([[544],{813:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findMin = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> lo=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> hi=nums.length<span class=\\"hljs-number\\">-1</span>\\n    <span class=\\"hljs-keyword\\">while</span>(lo&lt;=hi){\\n        <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.floor((lo+hi)/<span class=\\"hljs-number\\">2</span>)\\n        <span class=\\"hljs-keyword\\">if</span>(nums[mid]&lt;=nums[nums.length<span class=\\"hljs-number\\">-1</span>]){\\n            hi=mid<span class=\\"hljs-number\\">-1</span>\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            lo=mid+<span class=\\"hljs-number\\">1</span>\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> nums[lo]\\n};\\n</code></pre>\\n","<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">findMin</span><span class=\\"hljs-params\\">(self, nums)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type nums: List[int]\\n        :rtype: int\\n        \\"\\"\\"</span>\\n        lo,hi=<span class=\\"hljs-number\\">0</span>,len(nums)<span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">while</span> lo&lt;=hi:\\n            mid=(lo+hi) // <span class=\\"hljs-number\\">2</span>\\n            <span class=\\"hljs-keyword\\">if</span> nums[mid]&lt;=nums[<span class=\\"hljs-number\\">-1</span>]:\\n                hi=mid<span class=\\"hljs-number\\">-1</span>\\n            <span class=\\"hljs-keyword\\">else</span>:\\n                lo=mid+<span class=\\"hljs-number\\">1</span>\\n        <span class=\\"hljs-keyword\\">return</span> nums[lo]\\n                \\n</code></pre>\\n"],"titleSlug":"find-minimum-in-rotated-sorted-array","hasThinking":false,"content":"\u5df2\u77e5\u4e00\u4e2a\u957f\u5ea6\u4e3a <code>n</code> \u7684\u6570\u7ec4\uff0c\u9884\u5148\u6309\u7167\u5347\u5e8f\u6392\u5217\uff0c\u7ecf\u7531 <code>1</code> \u5230 <code>n</code> \u6b21 <strong>\u65cb\u8f6c</strong> \u540e\uff0c\u5f97\u5230\u8f93\u5165\u6570\u7ec4\u3002\u4f8b\u5982\uff0c\u539f\u6570\u7ec4 <code>nums = [0,1,2,4,5,6,7]</code> \u5728\u53d8\u5316\u540e\u53ef\u80fd\u5f97\u5230\uff1a\\n<ul>\\n\\t<li>\u82e5\u65cb\u8f6c <code>4</code> \u6b21\uff0c\u5219\u53ef\u4ee5\u5f97\u5230 <code>[4,5,6,7,0,1,2]</code></li>\\n\\t<li>\u82e5\u65cb\u8f6c <code>7</code> \u6b21\uff0c\u5219\u53ef\u4ee5\u5f97\u5230 <code>[0,1,2,4,5,6,7]</code></li>\\n</ul>\\n\\n<p>\u6ce8\u610f\uff0c\u6570\u7ec4 <code>[a[0], a[1], a[2], ..., a[n-1]]</code> <strong>\u65cb\u8f6c\u4e00\u6b21</strong> \u7684\u7ed3\u679c\u4e3a\u6570\u7ec4 <code>[a[n-1], a[0], a[1], a[2], ..., a[n-2]]</code> \u3002</p>\\n\\n<p>\u7ed9\u4f60\u4e00\u4e2a\u5143\u7d20\u503c <strong>\u4e92\u4e0d\u76f8\u540c</strong> \u7684\u6570\u7ec4 <code>nums</code> \uff0c\u5b83\u539f\u6765\u662f\u4e00\u4e2a\u5347\u5e8f\u6392\u5217\u7684\u6570\u7ec4\uff0c\u5e76\u6309\u4e0a\u8ff0\u60c5\u5f62\u8fdb\u884c\u4e86\u591a\u6b21\u65cb\u8f6c\u3002\u8bf7\u4f60\u627e\u51fa\u5e76\u8fd4\u56de\u6570\u7ec4\u4e2d\u7684 <strong>\u6700\u5c0f\u5143\u7d20</strong> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [3,4,5,1,2]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>\u539f\u6570\u7ec4\u4e3a [1,2,3,4,5] \uff0c\u65cb\u8f6c 3 \u6b21\u5f97\u5230\u8f93\u5165\u6570\u7ec4\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [4,5,6,7,0,1,2]\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n<strong>\u89e3\u91ca\uff1a</strong>\u539f\u6570\u7ec4\u4e3a [0,1,2,4,5,6,7] \uff0c\u65cb\u8f6c 4 \u6b21\u5f97\u5230\u8f93\u5165\u6570\u7ec4\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [11,13,15,17]\\n<strong>\u8f93\u51fa\uff1a</strong>11\\n<strong>\u89e3\u91ca\uff1a</strong>\u539f\u6570\u7ec4\u4e3a [11,13,15,17] \uff0c\u65cb\u8f6c 4 \u6b21\u5f97\u5230\u8f93\u5165\u6570\u7ec4\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>n == nums.length</code></li>\\n\\t<li><code>1 <= n <= 5000</code></li>\\n\\t<li><code>-5000 <= nums[i] <= 5000</code></li>\\n\\t<li><code>nums</code> \u4e2d\u7684\u6240\u6709\u6574\u6570 <strong>\u4e92\u4e0d\u76f8\u540c</strong></li>\\n\\t<li><code>nums</code> \u539f\u6765\u662f\u4e00\u4e2a\u5347\u5e8f\u6392\u5e8f\u7684\u6570\u7ec4\uff0c\u5e76\u8fdb\u884c\u4e86 <code>1</code> \u81f3 <code>n</code> \u6b21\u65cb\u8f6c</li>\\n</ul>\\n","title":"153. \u5bfb\u627e\u65cb\u8f6c\u6392\u5e8f\u6570\u7ec4\u4e2d\u7684\u6700\u5c0f\u503c","relatedTags":["\u6570\u7ec4","\u4e8c\u5206\u67e5\u627e"],"difficult":"Middle","lang":["javascript","python"],"uniqueID":"153"}')}}]);